import {cn} from '@/lib/utils';

import * as React from 'react';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type AgentFollowUpChipsProps = React.ComponentProps<'div'> & {
  /** Suggestion strings to render as clickable chips. */
  suggestions: string[];
  /** Called with the chip text when a chip is clicked. */
  onSelect: (text: string) => void;
};

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * A flex-wrap row of contextual suggestion chips.
 * Each chip is a bordered button that calls `onSelect` with its text on click.
 *
 * Intended to appear below an agent response to offer follow-up prompts.
 *
 * @wcag 2.1.1 Keyboard — each chip is a native button, activatable by Enter/Space
 * @wcag 4.1.2 Name, Role, Value — accessible name comes from chip text content
 */
function AgentFollowUpChips({
  suggestions,
  onSelect,
  className,
  ...props
}: AgentFollowUpChipsProps) {
  if (suggestions.length === 0) return null;

  return (
    <div
      data-slot="follow-up-chips"
      className={cn('flex flex-wrap gap-1.5', className)}
      {...props}
    >
      {suggestions.map(text => (
        <button
          key={text}
          type="button"
          onClick={() => onSelect(text)}
          className={cn(
            'rounded-dds-radius-sm border border-border-subtle px-2.5 py-1 text-xs text-muted-foreground',
            'transition-colors duration-100',
            'hover:border-border hover:text-foreground',
            'focus-visible:ring-2 focus-visible:ring-ring focus-visible:outline-none',
            'disabled:pointer-events-none disabled:opacity-50'
          )}
        >
          {text}
        </button>
      ))}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {AgentFollowUpChips};
export type {AgentFollowUpChipsProps};
